## Section1(not reported)
## Problem1(3.5.8.31)
## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "contextFiniteSolutionSets.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context("Fraction");
Context()->noreduce('(-x)+y', '(-x)-y');
do {
  @den = random_coprime([2..6],[2..6]);
  $k = random(2,7);
  @den = map{$_*$k}(@den);
  @den = random_subset(4,(@den,1,1));
  @num = (
    (random_coprime([1..8],[$den[0]]))[0],
    (random_coprime([-8..-1,1..8],[$den[1]]))[0],
    (random_coprime([-8..-1,1..8],[$den[2]]))[0],
    (random_coprime([-8..-1,1..8],[$den[3]]))[0]
  );
  @c = map{Fraction($num[$_]/$den[$_])} (0..3);
} until ($c[0] != $c[2]);
$left = Formula("$c[0] x + $c[1]")->reduce;
$right = Formula("$c[2] x + $c[3]")->reduce;
$sol = ($c[3] - $c[1])/($c[0] - $c[2]);
Context("FiniteSolutionSets");
$solution = Formula("{$sol}");
$lcd = lcm(@den);

############################################################
# Body
############################################################

BEGIN_PGML
Solve the given equation. Practice clearing the denominator(s) as a first step.

[`[$left] = [$right]`]

[@KeyboardInstructions('What LCD will you use?')@]**

[_]{$lcd}{4}

[@KeyboardInstructions('Solve the equation.')@]**

[_]{$solution}{16}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
